{
  "mode": "method",
  "tests": [
    {
      "name": "custom_signature_loads_inline_reply",
      "input": {
        "action": "reply",
        "inline": true,
        "signature": "Best regards, John Doe"
      },
      "output": {
        "signatureLoaded": true
      },
      "notes": "Validates that the custom signature loads correctly in an inline reply."
    },
    {
      "name": "custom_signature_not_loaded_popout",
      "input": {
        "action": "reply",
        "inline": false,
        "signature": "Best regards, John Doe"
      },
      "output": {
        "signatureLoaded": true
      },
      "notes": "Ensures that the signature loads correctly when the compose window is popped out."
    },
    {
      "name": "signature_modification_triggers_alert",
      "input": {
        "action": "modify_signature",
        "newContent": "Best regards, John Doe\nP.S. See you soon!"
      },
      "output": {
        "smartAlertTriggered": true
      },
      "notes": "Confirms that modifying the signature triggers the Smart Alerts dialog."
    },
    {
      "name": "signature_modification_no_alert",
      "input": {
        "action": "modify_signature",
        "newContent": "Best regards, John Doe"
      },
      "output": {
        "smartAlertTriggered": false
      },
      "notes": "Tests that no alert is triggered when the signature content remains unchanged."
    },
    {
      "name": "empty_signature_on_reply",
      "input": {
        "action": "reply",
        "inline": true,
        "signature": ""
      },
      "output": {
        "signatureLoaded": false
      },
      "notes": "Checks behavior when the signature is empty during an inline reply."
    },
    {
      "name": "signature_insertion_failure",
      "input": {
        "action": "insert_signature",
        "error": "signature_insertion_failed"
      },
      "output": {
        "signatureLoaded": false
      },
      "notes": "Simulates a failure in signature insertion to ensure proper error handling."
    },
    {
      "name": "multiple_modifications_triggers_alert",
      "input": {
        "action": "modify_signature",
        "newContent": "Best regards, John Doe\nP.S. See you soon!",
        "additionalContent": "Looking forward to our meeting."
      },
      "output": {
        "smartAlertTriggered": true
      },
      "notes": "Validates that multiple modifications trigger the Smart Alerts dialog."
    },
    {
      "name": "signature_loads_after_modification",
      "input": {
        "action": "modify_signature",
        "newContent": "Best regards, John Doe"
      },
      "output": {
        "signatureLoaded": true
      },
      "notes": "Ensures that the signature loads correctly after modification."
    }
  ],
  "assumptions": "The add-in is properly installed and configured to handle signatures.",
  "notes": "Tests cover both normal and edge cases to ensure robust functionality."
}
